import numpy as np

def _doc2ids(label_one_hot: bool, s2_label_dict: dict, data_list: dict, maxlen: int, s2_label: bool, char2idx: dict, ftype: int) -> dict:
    doc2ids = {}

    for f, seqs in data_list.items():
        if ftype in [1, 3]:
            if f == 'label':
                if label_one_hot:
                    num_classes = len(s2_label_dict)
                    labels = [int(seq.strip()) for seq in seqs]
                    one_hot_labels = np.zeros((len(labels), num_classes))
                    for i, label in enumerate(labels):
                        if 0 <= label < num_classes:
                            one_hot_labels[i, label] = 1
                    doc2ids[f] = one_hot_labels
                else:
                    doc2ids[f] = np.array([int(seq.strip()) for seq in seqs])
            else:
                sequences = []
                for seq in seqs:
                    indices = [char2idx.get(char, 1) for char in seq]
                    padded_indices = indices[:maxlen] + [0] * (maxlen - len(indices))
                    sequences.append(padded_indices)
                doc2ids[f] = np.array(sequences)

        elif ftype == 2:
            if f == 's2' and s2_label:
                sequences = []
                for seq in seqs:
                    index = s2_label_dict.get(seq.strip(), 1)
                    padded_indices = [index] + [0] * (maxlen - 1)
                    sequences.append(padded_indices)
                doc2ids[f] = np.array(sequences)
            else:
                sequences = []
                for seq in seqs:
                    indices = [char2idx.get(char, 1) for char in seq]
                    padded_indices = indices[:maxlen] + [0] * (maxlen - len(indices))
                    sequences.append(padded_indices)
                doc2ids[f] = np.array(sequences)

    return doc2ids
