import numpy as np

def keras_pad_seqs(sequences, maxlen, dtype, padding, truncating, value):
    # Determine the number of samples
    num_samples = len(sequences) if hasattr(sequences, '__len__') else 0

    # Calculate the lengths of each sequence
    lengths = [len(seq) if hasattr(seq, '__len__') else 0 for seq in sequences]

    # Determine maxlen if not provided
    if maxlen is None:
        maxlen = np.max(lengths)

    # Determine the sample shape
    sample_shape = ()
    for seq in sequences:
        if len(seq) > 0:
            sample_shape = np.asarray(seq).shape[1:]
            break

    # Initialize the output array
    x = np.full((num_samples, maxlen) + sample_shape, value, dtype=dtype)

    # Process each sequence
    for idx, seq in enumerate(sequences):
        if len(seq) == 0:
            continue

        # Truncate the sequence
        if truncating == 'pre':
            trunc = seq[-maxlen:]
        elif truncating == 'post':
            trunc = seq[:maxlen]
        else:
            raise ValueError(f"Truncating type '{truncating}' not understood")

        # Convert to array
        trunc = np.asarray(trunc, dtype=dtype)

        # Determine the slice for padding
        if padding == 'post':
            x[idx, :len(trunc)] = trunc
        elif padding == 'pre':
            x[idx, -len(trunc):] = trunc
        else:
            raise ValueError(f"Padding type '{padding}' not understood")

    return x
