import numpy as np

def get_cm(i, cm_coef, alpha, cl_ext, cd_ext, alpha_low_deg, alpha_high_deg, cm0):
    cm_lookup = {
        -180: -0.1, -170: -0.2, -160: -0.3, 160: 0.3, 170: 0.2, 180: 0.1
    }

    cm_new = cm0

    if alpha[i] < alpha_low_deg or alpha[i] > alpha_high_deg:
        if -165 <= alpha[i] <= 165:
            if abs(alpha[i]) < 0.01:
                cm_new = cm0
            elif alpha[i] > 0:
                x = cm_coef * np.tan(np.radians(alpha[i]) - np.pi / 2) + 0.25
                cm_new = cm0 - x * (cl_ext[i] * np.cos(np.radians(alpha[i])) + cd_ext[i] * np.sin(np.radians(alpha[i])))
            else:
                x = cm_coef * np.tan(-np.radians(alpha[i]) - np.pi / 2) + 0.25
                cm_new = -(cm0 - x * (-cl_ext[i] * np.cos(-np.radians(alpha[i])) + cd_ext[i] * np.sin(-np.radians(alpha[i]))))
        else:
            cm_new = cm_lookup.get(alpha[i], cm0)

    return cm_new
