import numpy as np

def toy_generator(dataset: str, N: int) -> torch.Tensor:
    if dataset == 'gaussian':
        data = np.random.randn(N, 2) * 1.5

    elif dataset == 'mog':
        angles = np.linspace(0, 2 * np.pi, 8, endpoint=False)
        centers = np.stack([np.cos(angles), np.sin(angles)], axis=1) * 0.8
        data = []
        for center in centers:
            points = np.random.randn(N // 8, 2) * 0.1 + center
            data.append(points)
        data = np.concatenate(data, axis=0)
        if len(data) < N:
            data = np.concatenate([data, np.random.randn(N - len(data), 2) * 0.1 + centers[0]], axis=0)

    elif dataset == 'circles':
        radii = [0.5, 1.0, 1.5]
        data = []
        for r in radii:
            angles = np.random.rand(N // 3) * 2 * np.pi
            points = np.stack([r * np.cos(angles), r * np.sin(angles)], axis=1)
            points += np.random.randn(*points.shape) * 0.01
            data.append(points)
        data = np.concatenate(data, axis=0)
        if len(data) < N:
            data = np.concatenate([data, np.random.randn(N - len(data), 2) * 0.01 + data[0]], axis=0)

    elif dataset == 'circle':
        angles = np.random.rand(N) * 2 * np.pi
        data = np.stack([np.cos(angles), np.sin(angles)], axis=1) * 0.9

    elif dataset == 'checker':
        data = []
        for i in range(4):
            for j in range(4):
                if (i + j) % 2 == 0:
                    points = np.random.rand(N // 8, 2) * 0.9 + np.array([i, j])
                    data.append(points)
        data = np.concatenate(data, axis=0)
        if len(data) < N:
            data = np.concatenate([data, np.random.rand(N - len(data), 2) * 0.9 + data[0]], axis=0)

    elif dataset == 'grid':
        grid_size = int(np.sqrt(N))
        x = np.linspace(-1, 1, grid_size)
        y = np.linspace(-1, 1, grid_size)
        xv, yv = np.meshgrid(x, y)
        data = np.stack([xv.flatten(), yv.flatten()], axis=1) * 0.8
        data += np.random.randn(*data.shape) * 0.05
        if len(data) < N:
            data = np.concatenate([data, np.random.randn(N - len(data), 2) * 0.05 + data[0]], axis=0)

    else:
        raise ValueError(f"Unknown dataset type: {dataset}")

    return torch.tensor(data[:N], dtype=torch.float32)
