import numpy as np
from scipy.signal import argrelextrema

def idxsOfRelativeExtrema(x, maxima, allowEq, axis):
    # Convert input to a numpy array
    x = np.asarray(x)

    # Handle empty input
    if x.size == 0:
        return np.array([0])

    # Handle single element input
    if x.size == 1:
        return np.array([0])

    # Determine padding value
    pad = -np.inf if maxima else np.inf

    # Select comparison function
    if maxima:
        comp_func = np.greater_equal if allowEq else np.greater
    else:
        comp_func = np.less_equal if allowEq else np.less

    # Handle one-dimensional input
    if x.ndim == 1:
        # Pad the array
        padded_x = np.concatenate(([pad], x, [pad]))
        # Find relative extrema
        extrema_indices = argrelextrema(padded_x, comp_func, order=1)[0]
        # Adjust indices to account for padding
        return extrema_indices - 1

    # Handle two-dimensional input
    elif x.ndim == 2:
        if axis == 0:
            # Pad along rows
            padded_x = np.vstack((np.full((1, x.shape[1]), pad), x, np.full((1, x.shape[1]), pad)))
            extrema_indices = argrelextrema(padded_x, comp_func, axis=0, order=1)
        elif axis == 1:
            # Pad along columns
            padded_x = np.hstack((np.full((x.shape[0], 1), pad), x, np.full((x.shape[0], 1), pad)))
            extrema_indices = argrelextrema(padded_x, comp_func, axis=1, order=1)
        else:
            raise ValueError("Axis must be 0 or 1 for 2D arrays.")

        # Adjust indices to account for padding
        return tuple(idx - 1 for idx in extrema_indices)

    else:
        raise ValueError("Input array must be 1D or 2D.")
