import numpy as np

def _mask_to_limits(a, limits, inclusive):
    lower_limit, upper_limit = limits
    lower_inclusive, upper_inclusive = inclusive

    if lower_limit is not None:
        if lower_inclusive:
            mask_lower = a >= lower_limit
        else:
            mask_lower = a > lower_limit
    else:
        mask_lower = np.ones(a.shape, dtype=bool)

    if upper_limit is not None:
        if upper_inclusive:
            mask_upper = a <= upper_limit
        else:
            mask_upper = a < upper_limit
    else:
        mask_upper = np.ones(a.shape, dtype=bool)

    return np.ma.masked_array(a, mask=~(mask_lower & mask_upper))

def tsem(a, limits=None, inclusive=(True, True), axis=None, ddof=1):
    a = np.asarray(a)

    if limits is None:
        if a.size == 0:
            return np.nan
        return np.std(a, ddof=ddof, axis=axis) / np.sqrt(a.size)

    am = _mask_to_limits(a, limits, inclusive)

    count = np.sum(~am.mask, axis=axis)
    if np.any(count == 0):
        return np.nan

    variance = np.ma.var(am, ddof=ddof, axis=axis)
    sem = np.sqrt(variance) / np.sqrt(count)

    return sem

# Example usage
a = np.array([-1.5, -2.3, 0.5, 1.2, 3.4])
limits = (-2.0, 2.0)
inclusive = (True, False)
axis = None
ddof = 1

result = tsem(a, limits, inclusive, axis, ddof)
print(result)  # Output: 0.8089774066341066
