import numpy as np

def sp1(data, maxvalue, issuccessful):
    # Input validation
    if not isinstance(data, (list, tuple, np.ndarray)):
        return (np.nan, np.nan, np.nan)

    if issuccessful is not None:
        if not isinstance(issuccessful, (list, tuple, np.ndarray)):
            return (np.nan, np.nan, np.nan)
        if len(data) != len(issuccessful):
            return (np.nan, np.nan, np.nan)

    # Data cleaning
    dat = [d for d in data if not np.isnan(d)]
    if issuccessful is not None:
        issuccessful = [issuccessful[i] for i in range(len(data)) if not np.isnan(data[i])]

    # Handling empty data
    if not dat:
        return (np.nan, np.nan, np.nan)

    # Filtering data based on success
    if issuccessful is not None:
        successful_data = [dat[i] for i in range(len(dat)) if issuccessful[i]]
    else:
        successful_data = [d for d in dat if d < maxvalue]

    # Calculating success ratio
    N = len(dat)
    successful_count = len(successful_data)
    succ = successful_count / N if N > 0 else 0

    # Returning results
    if succ == 0:
        return (np.inf, 0.0, 0)
    else:
        mean_successful = np.mean(successful_data) if successful_data else 0
        adjusted_mean = mean_successful / succ
        return (adjusted_mean, succ, successful_count)
