import numpy as np

def sp(data, maxvalue, issuccessful, allowinf):
    # Check if data is iterable
    try:
        iter(data)
    except TypeError:
        return (np.nan, np.nan, np.nan)

    # Validate issuccessful
    if issuccessful is not None:
        try:
            iter(issuccessful)
            if len(issuccessful) != len(data):
                issuccessful = None
        except TypeError:
            issuccessful = None

    # Filter out NaN values from data
    dat = [x for x in data if not np.isnan(x)]
    N = len(dat)

    # If no valid data, return NaNs
    if N == 0:
        return (np.nan, np.nan, np.nan)

    # Sort the valid data
    dat.sort()

    # Filter successful data
    if issuccessful is not None:
        succdat = [dat[i] for i in range(N) if issuccessful[i]]
    else:
        succdat = [x for x in dat if x < maxvalue]

    # Calculate success rate
    succ = len(succdat) / N if N > 0 else 0

    # Calculate result
    if succ == 0:
        res = float('inf') if allowinf else sum(dat)
    else:
        res = sum(dat) / len(succdat) if len(succdat) > 0 else np.nan

    return (res, succ, len(succdat))
