import pandas as pd
import numpy as np

def to_dataframe(ifp: dict, interactions: list, count: bool, dtype: type, drop_empty: bool, index_col: str) -> pd.DataFrame:
    # Determine the default dtype and empty_value based on count
    if dtype is None:
        dtype = np.uint8 if count else bool
    empty_value = 0 if count else False

    # Identify unique residue pairs
    residue_pairs = sorted(set(pair for frame in ifp.values() for pair in frame.keys()))

    # Initialize data storage
    data = {pair: {interaction: [] for interaction in interactions} for pair in residue_pairs}
    index = []

    # Iterate over frames
    for frame_idx, frame_data in ifp.items():
        index.append(frame_idx)
        for pair in residue_pairs:
            pair_data = frame_data.get(pair, {})
            for interaction in interactions:
                if count:
                    # Count occurrences of each interaction
                    value = len(pair_data.get(interaction, ()))
                else:
                    # Check presence of each interaction
                    value = interaction in pair_data
                data[pair][interaction].append(value)

    # Construct DataFrame values
    values = []
    columns = []
    for pair in residue_pairs:
        for interaction in interactions:
            values.append(data[pair][interaction])
            columns.append((pair[0], pair[1], interaction))

    # Create MultiIndex for columns
    multi_index = pd.MultiIndex.from_tuples(columns, names=['ligand', 'protein', 'interaction'])

    # Create DataFrame
    df = pd.DataFrame(np.array(values).T, index=index, columns=multi_index, dtype=dtype)
    df.index.name = index_col

    # Drop empty columns if required
    if drop_empty:
        df = df.loc[:, (df != empty_value).any(axis=0)]

    return df

