import numpy as np
import scipy.special as sp

def second_order_score(y, mean, scale, shape, skewness):
    # Calculate the constant m1 using the gamma function
    m1 = np.sqrt(shape) * sp.gamma((shape - 1.0) / 2.0) / (np.sqrt(np.pi) * sp.gamma(shape / 2.0))

    # Adjust the mean based on skewness
    adjusted_mean = mean + (skewness - 1.0 / skewness) * scale * m1

    # Calculate the score based on the relationship between y and the adjusted mean
    if y - adjusted_mean >= 0:
        return (shape + 1) / shape * (y - adjusted_mean) / (np.power(skewness * scale, 2) + np.power(y - adjusted_mean, 2) / shape)
    else:
        return (shape + 1) / shape * (y - adjusted_mean) / (np.power(scale, 2) + np.power(skewness * (y - adjusted_mean), 2) / shape)
