import numpy as np
import pandas as pd

def survival_table_from_events(death_times, event_observed, birth_times, columns, weights, collapse, intervals):
    death_times = np.asarray(death_times)
    event_observed = np.asarray(event_observed)

    if birth_times is None:
        birth_times = np.zeros_like(death_times)
    else:
        birth_times = np.asarray(birth_times)

    if weights is None:
        weights = np.ones_like(death_times)
    else:
        weights = np.asarray(weights)

    df = pd.DataFrame({
        'event_at': death_times,
        'removed': weights,
        'observed': weights * event_observed
    })

    death_table = df.groupby('event_at').sum()
    death_table['censored'] = (death_table['removed'] - death_table['observed']).astype(int)

    births = pd.DataFrame({
        'event_at': birth_times,
        'entrance': weights
    })

    births_table = births.groupby('event_at').sum()

    event_table = death_table.join(births_table, how='outer').fillna(0)
    event_table = event_table.sort_index()

    event_table['at_risk'] = event_table['entrance'].cumsum() - event_table['removed'].cumsum().shift(1).fillna(0)

    if collapse or intervals is not None:
        event_table = _group_event_table_by_intervals(event_table, intervals)

    if not np.all(weights.astype(int) == weights):
        event_table = event_table.astype(float)
    else:
        event_table = event_table.astype(int)

    return event_table[columns]

def _group_event_table_by_intervals(event_table, intervals):
    if intervals is None:
        return event_table

    intervals = np.asarray(intervals)
    grouped = event_table.groupby(pd.cut(event_table.index, intervals, right=False)).sum()
    grouped.index = intervals[:-1]
    return grouped
