import numpy as np

def rankdata(a, method):
    a = np.ravel(np.asarray(a))
    n = len(a)
    sorter = np.argsort(a, kind='mergesort' if method == 'ordinal' else 'quicksort')
    inv = np.empty(n, dtype=int)
    inv[sorter] = np.arange(n)

    if method == 'ordinal':
        return inv.astype(np.float64) + 1

    sorted_a = a[sorter]
    obs = np.concatenate(([True], sorted_a[1:] != sorted_a[:-1]))
    dense_rank = np.cumsum(obs)[inv]

    if method == 'dense':
        return dense_rank.astype(np.float64)

    count = np.zeros(n, dtype=int)
    count[sorter] = np.arange(n)
    max_rank = np.cumsum(obs)[count]
    min_rank = max_rank - obs.cumsum() + 1

    if method == 'max':
        return max_rank.astype(np.float64)
    elif method == 'min':
        return min_rank.astype(np.float64)
    else:
        return ((max_rank + min_rank) / 2.0).astype(np.float64)
