import numpy as np

def logbins_numba(lo: float, hi: float, ratio: float, N: int, prepend_zero: bool) -> np.ndarray:
    lo = int(lo)
    hi = int(hi)

    if ratio > 1 and N == 0:
        N = int(np.log(hi / lo) / np.log(ratio))

    N = max(1, N)

    if N > 1:
        log_lo = np.log10(lo)
        log_hi = np.log10(hi)
        bins = np.logspace(log_lo, log_hi, num=N, base=10)
    else:
        bins = np.array([lo, hi])

    bins = np.unique(np.round(bins).astype(int))

    if bins[0] != lo:
        bins = np.insert(bins, 0, lo)
    if bins[-1] != hi:
        bins = np.append(bins, hi)

    if prepend_zero:
        bins = np.insert(bins, 0, 0)

    return bins
