def qam_mod(M):
    import numpy as np

    def gray_code(n):
        return n ^ (n >> 1)

    sqrtM = int(np.sqrt(M))
    special_cases = {
        8: {
            'gray': [0, 1, 3, 2, 7, 6, 4, 5],
            'constellation': [(-1-1j), (-1+1j), (1+1j), (1-1j), (0-2j), (2+0j), (0+2j), (-2+0j)]
        },
        32: {
            'gray': [0] * 32,
            'constellation': []
        }
    }

    if M in special_cases:
        gray = special_cases[M]['gray']
        constellation = special_cases[M]['constellation']
        if M == 32:
            for i in range(8):
                for j in range(4):
                    idx = i * 4 + j
                    gray[idx] = gray_code(idx)
                    constellation.append((2 * i - 7 + 1j * (2 * j - 3)))
    else:
        gray = [gray_code(i) for i in range(M)]
        constellation = []
        for i in range(sqrtM):
            for j in range(sqrtM):
                constellation.append((2 * i - sqrtM + 1 + 1j * (2 * j - sqrtM + 1)))

    map_table = {gray[i]: constellation[i] for i in range(M)}
    demap_table = {constellation[i]: gray[i] for i in range(M)}

    return map_table, demap_table
