import numpy as np

def process_parameters_psd(dim, mean, cov):
    # Step 1: Dimension Initialization
    if dim is None:
        dim = 1

    # Step 2: Mean Processing
    if mean is not None:
        mean = np.array(mean, dtype=float)
        dim = mean.size
    elif cov is not None:
        cov = np.array(cov, dtype=float)
        if cov.ndim == 1:
            dim = 1
        else:
            dim = cov.shape[0]

    # Step 3: Default Mean and Covariance Initialization
    if mean is None:
        mean = np.zeros(dim, dtype=float)
    if cov is None:
        cov = 1.0

    # Step 4: Reshaping for Single Dimension
    if dim == 1:
        mean = mean.reshape(1)
        if np.isscalar(cov) or cov.ndim == 0:
            cov = np.array([[cov]], dtype=float)
        elif cov.ndim == 1:
            cov = np.diag(cov)

    # Step 5: Covariance Matrix Formatting
    if np.isscalar(cov) or cov.ndim == 0:
        cov = cov * np.eye(dim, dtype=float)
    elif cov.ndim == 1:
        cov = np.diag(cov)
    elif cov.ndim == 2:
        if cov.shape != (dim, dim):
            if cov.shape[0] != cov.shape[1]:
                cov = np.eye(dim, dtype=float)
            else:
                cov = np.zeros((dim, dim), dtype=float)
    else:
        cov = np.eye(dim, dtype=float)

    # Step 6: Return Values
    return dim, mean, cov
