import pandas as pd

def unmelt(df: pd.DataFrame) -> pd.DataFrame:
    if not isinstance(df, pd.DataFrame):
        return df

    # Check if the DataFrame has a single column named 'Value'
    if len(df.columns) == 1 and df.columns[0] == 'Value':
        # If the DataFrame has a single index
        if isinstance(df.index, pd.Index):
            # Create a DataFrame with columns from the index and values from the 'Value' column
            return pd.DataFrame([df['Value'].values], columns=df.index)

        # If the DataFrame has a MultiIndex
        elif isinstance(df.index, pd.MultiIndex):
            # Get unique values from the first level of the index
            names = df.index.get_level_values(0).unique()
            # Create a dictionary to hold the unmelted data
            data = {name: df.xs(name, level=0)['Value'].values for name in names}
            # Create a DataFrame from the dictionary
            return pd.DataFrame(data)

    # If the DataFrame does not meet the single 'Value' column condition, return it as is
    return df
