import pandas as pd
import re

def process_fewshot_for_moe_comparison(measurements_dict):
    def _parse_column(column_name):
        match = re.match(r'z/([^_]+)_(\d+)shot_(.+)', column_name)
        if match and 'best_l2' not in column_name:
            dataset, shot, metric_type = match.groups()
            return column_name, (f"{shot}shot_{metric_type}", f"few-shot {dataset}")
        return None, None

    rows = []

    for model_name in ('MoE', '[Det]_4', '[MoE]_4'):
        if model_name in measurements_dict:
            mean_series = measurements_dict[model_name].mean(axis=0)
            assert isinstance(mean_series, pd.Series)
            fewshot_dict = mean_series.to_dict()

            parsed_columns = {key: _parse_column(key) for key in fewshot_dict.keys()}
            fewshot_dict = {parsed_columns[key][1]: value for key, value in fewshot_dict.items() if parsed_columns[key][1] is not None}
            fewshot_dict['model_name'] = model_name

            rows.append(fewshot_dict)

    df = pd.DataFrame(rows).set_index('model_name')
    df.columns = pd.MultiIndex.from_tuples(df.columns, names=['metric', 'dataset'])

    return df
