import pandas as pd

def cat_var(data, col_excl=None, return_cat=True):
    # Create a copy of the DataFrame to avoid modifying the original
    df = data.copy()

    # Determine non-numeric columns
    if col_excl is None:
        col_excl = []
    non_numeric_cols = df.select_dtypes(exclude=['number']).columns.difference(col_excl)

    # Prepare the DataFrame for categorical variables
    cat_var_df = pd.DataFrame({
        'cat_ind': [df.columns.get_loc(col) for col in non_numeric_cols],
        'cat_name': non_numeric_cols
    })

    # Initialize mappers
    inv_mapper = {}
    mapper = {}

    # Process each non-numeric column
    for col in non_numeric_cols:
        # Convert column to string if it contains 'date'
        if 'date' in col.lower():
            df[col] = df[col].astype(str)

        # Create mapping for the column
        unique_values = df[col].dropna().unique()
        col_mapper = {val: idx for idx, val in enumerate(unique_values)}
        col_inv_mapper = {idx: val for val, idx in col_mapper.items()}

        # Map the column values to integers
        df[col] = df[col].map(col_mapper).fillna(0).astype(int)

        # Store the mappers
        mapper[col] = col_mapper
        inv_mapper[col] = col_inv_mapper

    # Convert columns back to categorical if requested
    if return_cat:
        for col in non_numeric_cols:
            df[col] = df[col].astype('category')

    return df, cat_var_df, inv_mapper, mapper
