import numpy as np
import pandas as pd
from sklearn.model_selection import LeavePGroupsOut
from sklearn.metrics import roc_curve, auc
from sklearn.preprocessing import label_binarize

def hold_one_subject_knn(tcrrep, max_k, inverse_distance_weight, account_for_prior, power):
    def _cv_split_hold_out_by_subject_using_sklearn(clone_df):
        lpgo = LeavePGroupsOut(n_groups=1)
        groups = clone_df['subject']
        return lpgo.split(clone_df, groups=groups)

    def knn(distances, train_indices, test_indices, k, inverse_distance_weight, power):
        test_distances = distances[test_indices][:, train_indices]
        sorted_indices = np.argsort(test_distances, axis=1)
        nearest_indices = sorted_indices[:, :k]
        nearest_distances = np.take_along_axis(test_distances, nearest_indices, axis=1)

        if inverse_distance_weight:
            weights = 1 / np.power(nearest_distances, power)
            weights[np.isinf(weights)] = 0
        else:
            weights = np.ones_like(nearest_distances)

        return nearest_indices, weights

    def _calc_idw_weighted_score(nearest_indices, weights, train_labels, unique_epitopes):
        scores = np.zeros((nearest_indices.shape[0], len(unique_epitopes)))
        for i, indices in enumerate(nearest_indices):
            for j, epitope in enumerate(unique_epitopes):
                mask = train_labels[indices] == epitope
                scores[i, j] = np.sum(weights[i, mask])
        return scores

    def _calc_frequency(nearest_indices, train_labels, unique_epitopes):
        scores = np.zeros((nearest_indices.shape[0], len(unique_epitopes)))
        for i, indices in enumerate(nearest_indices):
            for j, epitope in enumerate(unique_epitopes):
                scores[i, j] = np.sum(train_labels[indices] == epitope)
        return scores

    def _calc_prior_probabilities(train_labels, unique_epitopes):
        prior_probs = np.zeros(len(unique_epitopes))
        for i, epitope in enumerate(unique_epitopes):
            prior_probs[i] = np.mean(train_labels == epitope)
        return prior_probs

    def roc_pddf(y_true, y_score, unique_epitopes):
        roc_data = {}
        for i, epitope in enumerate(unique_epitopes):
            fpr, tpr, thresholds = roc_curve(y_true[:, i], y_score[:, i])
            roc_auc = auc(fpr, tpr)
            roc_data[epitope] = pd.DataFrame({'fpr': fpr, 'tpr': tpr, 'thr': thresholds, 'roc_auc': [roc_auc] * len(fpr)})
        return roc_data

    clone_df = tcrrep.clone_df
    my_cl = clone_df['epitope'].values
    unique_epitopes = np.unique(my_cl)
    my_d = tcrrep.paired_tcrdist

    cv_splits = _cv_split_hold_out_by_subject_using_sklearn(clone_df)
    all_scores = []
    all_true_labels = []

    for train_idx, test_idx in cv_splits:
        train_labels = my_cl[train_idx]
        test_labels = my_cl[test_idx]

        nearest_indices, weights = knn(my_d, train_idx, test_idx, max_k, inverse_distance_weight, power)

        if inverse_distance_weight:
            scores = _calc_idw_weighted_score(nearest_indices, weights, train_labels, unique_epitopes)
        else:
            scores = _calc_frequency(nearest_indices, train_labels, unique_epitopes)

        if account_for_prior:
            prior_probs = _calc_prior_probabilities(train_labels, unique_epitopes)
            scores *= prior_probs

        all_scores.append(scores)
        all_true_labels.append(label_binarize(test_labels, classes=unique_epitopes))

    all_scores = np.vstack(all_scores)
    all_true_labels = np.vstack(all_true_labels)

    return roc_pddf(all_true_labels, all_scores, unique_epitopes)
