import pandas as pd
import numpy as np

def reduce_mem_usage(df):
    start_mem_usg = df.memory_usage().sum() / 1024**2
    NAlist = []

    for col in df.columns:
        col_type = df[col].dtype

        if col_type != object:
            if pd.isnull(df[col]).any() or np.isinf(df[col]).any():
                NAlist.append(col)
                df[col].fillna(0, inplace=True)
                df[col].replace([np.inf, -np.inf], 0, inplace=True)

            is_int = False
            asint = df[col].fillna(0).astype(np.int64)
            result = (df[col] - asint).sum()
            if -0.01 < result < 0.01:
                is_int = True

            if is_int:
                min_val, max_val = df[col].min(), df[col].max()
                if min_val >= 0:
                    if max_val < 255:
                        df[col] = df[col].astype(np.uint8)
                    elif max_val < 65535:
                        df[col] = df[col].astype(np.uint16)
                    elif max_val < 4294967295:
                        df[col] = df[col].astype(np.uint32)
                    else:
                        df[col] = df[col].astype(np.uint64)
                else:
                    if np.iinfo(np.int8).min < min_val < np.iinfo(np.int8).max:
                        df[col] = df[col].astype(np.int8)
                    elif np.iinfo(np.int16).min < min_val < np.iinfo(np.int16).max:
                        df[col] = df[col].astype(np.int16)
                    elif np.iinfo(np.int32).min < min_val < np.iinfo(np.int32).max:
                        df[col] = df[col].astype(np.int32)
                    else:
                        df[col] = df[col].astype(np.int64)
            else:
                df[col] = df[col].astype(np.float32)

    end_mem_usg = df.memory_usage().sum() / 1024**2
    mem_usg_percentage = 100 * (start_mem_usg - end_mem_usg) / start_mem_usg

    return df, NAlist, mem_usg_percentage

# Example usage
data = {
    'col_0': [1, 2, 3, 4, 5],
    'col_1': [1.1, 2.2, 3.3, np.nan, 5.5],
    'col_2': [np.nan, np.inf, -np.inf, 4, 5],
    'col_3': [100000, 200000, 300000, 400000, 500000]
}

df = pd.DataFrame(data)
df_reduced, na_list, mem_usg_percentage = reduce_mem_usage(df)
