import pandas as pd

def categorical_value_counts(df: pd.DataFrame, is_single: bool, x_is_multi: bool, y_is_multi: bool) -> pd.DataFrame:
    if df.empty:
        return pd.DataFrame({'nan': [0]}, index=['nan'])

    def expand_column(col, is_multi):
        if is_multi:
            return df[col].str.get_dummies(sep=';')
        else:
            return pd.get_dummies(df[col])

    if is_single:
        x_dummies = expand_column('X', x_is_multi)
        counts = x_dummies.mul(df['W'], axis=0).sum().to_frame(name='Count')
        counts.loc['All'] = counts.sum()
        return counts

    x_dummies = expand_column('X', x_is_multi)
    y_dummies = expand_column('Y', y_is_multi)

    weighted_counts = x_dummies.T.dot(y_dummies.mul(df['W'], axis=0))
    weighted_counts['All'] = weighted_counts.sum(axis=1)
    weighted_counts.loc['All'] = weighted_counts.sum()

    weighted_counts.index.name = ('Question', 'Values')
    weighted_counts.columns.name = ('Question', 'Values')

    return weighted_counts

# Example usage
