import numpy as np
from scipy.stats import mode

def compute_mode(a):
    def mode_with_nan_policy(arr, nan_policy):
        if nan_policy == 'omit':
            arr = np.array(arr)
            if arr.size == 0:
                return ModeResult(mode=np.nan, count=0.0)
            valid_mask = ~np.isnan(arr)
            if not np.any(valid_mask):
                return ModeResult(mode=np.nan, count=0.0)
            arr = arr[valid_mask]
            if arr.size == 0:
                return ModeResult(mode=np.nan, count=0.0)
            m, c = mode(arr, axis=None)
            return ModeResult(mode=m[0], count=c[0])
        elif nan_policy == 'propagate':
            if np.isnan(arr).any():
                return ModeResult(mode=np.nan, count=0.0)
            m, c = mode(arr, axis=None)
            return ModeResult(mode=m[0], count=c[0])
        else:
            raise ValueError("Invalid nan_policy")

    class ModeResult:
        def __init__(self, mode, count):
            self.mode = mode
            self.count = count

        def __repr__(self):
            return f"ModeResult(mode={self.mode}, count={self.count})"

    # Empty Case
    empty_case = mode_with_nan_policy([], 'omit')

    # NaN Case
    nan_case = mode_with_nan_policy([np.nan], 'omit')

    # Mode Omit
    if a.size == 0:
        mode_omit = ModeResult(mode=np.array([]), count=np.array([]))
    else:
        mode_omit_modes = []
        mode_omit_counts = []
        for row in a:
            result = mode_with_nan_policy(row, 'omit')
            mode_omit_modes.append(result.mode)
            mode_omit_counts.append(result.count)
        mode_omit = ModeResult(mode=np.array(mode_omit_modes), count=np.array(mode_omit_counts))

    # Mode Propagate
    if a.size == 0:
        mode_propagate = ModeResult(mode=np.array([]), count=np.array([]))
    else:
        mode_propagate_modes = []
        mode_propagate_counts = []
        for row in a:
            result = mode_with_nan_policy(row, 'propagate')
            mode_propagate_modes.append(result.mode)
            mode_propagate_counts.append(result.count)
        mode_propagate = ModeResult(mode=np.array(mode_propagate_modes), count=np.array(mode_propagate_counts))

    # Empty Array Case
    empty_array_case = mode_with_nan_policy(np.array([[], []]), 'omit')

    return {
        'empty_case': empty_case,
        'nan_case': nan_case,
        'mode_omit': mode_omit,
        'mode_propagate': mode_propagate,
        'empty_array_case': empty_array_case
    }
