import numpy as np
from scipy.stats import mstats, normaltest, skewtest, kurtosistest

def process_data(input_data):
    # Convert input_data to a NumPy array if it is not already
    if not isinstance(input_data, np.ndarray):
        input_data = np.array(input_data)

    # Define the test functions for masked and non-masked data
    test_functions = {
        'normaltest': (mstats.normaltest, normaltest),
        'skewtest': (mstats.skewtest, skewtest),
        'kurtosistest': (mstats.kurtosistest, kurtosistest)
    }

    # Perform the tests and collect results
