import numpy as np
from scipy import sparse

def make_system(A, x, b, formats=None):
    # Convert A to the desired sparse format if specified
    if formats:
        if 'csr' in formats:
            if not sparse.isspmatrix_csr(A):
                A = A.tocsr() if sparse.isspmatrix(A) else sparse.csr_matrix(A)
        else:
            if not any(sparse.isspmatrix_format(A) for format in formats):
                A = sparse.csr_matrix(A)  # Default to CSR if no match

    # Convert x and b to numpy arrays if they are not already
    x = np.asarray(x).flatten()
    b = np.asarray(b).flatten()

    # Get the shape of A
    M, N = A.shape

    # Ensure A is square by replacing with identity if necessary
    if M != N:
        A = sparse.eye(M, format='csr')

    # Ensure x and b are of correct shape
    if x.shape[0] != M:
        x = np.zeros(M)
    if b.shape[0] != M:
        b = np.ones(M)

    # Check data types and ensure consistency
    dtype = np.result_type(A.dtype, x.dtype, b.dtype)
    if A.dtype != dtype:
        A = A.astype(dtype)
    if x.dtype != dtype:
        x = x.astype(dtype)
    if b.dtype != dtype:
        b = b.astype(dtype)

    return A, x, b
