import numpy as np
from scipy.spatial.distance import pdist, squareform
from scipy.stats import t

def preprocess_data(x, y):
    if x.ndim == 1:
        x = x[:, np.newaxis]
    if y.ndim == 1:
        y = y[:, np.newaxis]
    return x, y

def compute_distance_matrix(data):
    return squareform(pdist(data, metric='euclidean'))

def double_center(matrix):
    n = matrix.shape[0]
    row_mean = np.mean(matrix, axis=1, keepdims=True)
    col_mean = np.mean(matrix, axis=0, keepdims=True)
    total_mean = np.mean(matrix)
    return matrix - row_mean - col_mean + total_mean

def u_center(matrix):
    n = matrix.shape[0]
    row_mean = np.mean(matrix, axis=1, keepdims=True)
    col_mean = np.mean(matrix, axis=0, keepdims=True)
    total_mean = np.mean(matrix)
    return matrix - row_mean - col_mean + total_mean

def compute_distance_correlation(x, y, bias_corrected):
    n = x.shape[0]
    a = compute_distance_matrix(x)
    b = compute_distance_matrix(y)

    if bias_corrected:
        A = u_center(a)
        B = u_center(b)
        dcov_xy = np.sum(A * B) / (n * (n - 3))
        dcov_xx = np.sum(A * A) / (n * (n - 3))
        dcov_yy = np.sum(B * B) / (n * (n - 3))
    else:
        A = double_center(a)
        B = double_center(b)
        dcov_xy = np.mean(A * B)
        dcov_xx = np.mean(A * A)
        dcov_yy = np.mean(B * B)

    if dcov_xx > 0 and dcov_yy > 0:
        dcorr = np.sqrt(dcov_xy / np.sqrt(dcov_xx * dcov_yy))
    else:
        dcorr = 0.0

    return dcorr, dcov_xy, dcov_xx, dcov_yy

def post_process_distance_correlation(dcorr, dcov_xy, dcov_xx, dcov_yy, n, bias_corrected, ttest):
    result = {'dcorr': dcorr}

    if bias_corrected:
        dcorr_squared = dcov_xy / np.sqrt(dcov_xx * dcov_yy)
        result['dcorr_squared'] = dcorr_squared

    if ttest:
        if bias_corrected:
            df = n * (n - 3) / 2
        else:
            df = n - 2
        t_stat = np.sqrt(df) * dcorr / np.sqrt(1 - dcorr**2)
        p_value = 2 * (1 - t.cdf(np.abs(t_stat), df))
        result.update({'t': t_stat, 'p': p_value, 'df': df})

    return result

def distance_correlation(x: np.ndarray, y: np.ndarray, bias_corrected: bool = True, ttest: bool = True) -> dict:
    x, y = preprocess_data(x, y)
    n = x.shape[0]

    dcorr, dcov_xy, dcov_xx, dcov_yy = compute_distance_correlation(x, y, bias_corrected)

    return post_process_distance_correlation(dcorr, dcov_xy, dcov_xx, dcov_yy, n, bias_corrected, ttest)
