import numpy as np
from typing import Union, Tuple

def savitzky_golay2d(z: np.ndarray, window: int, order: int, deriv: Union[None, int, str]) -> Union[np.ndarray, Tuple[np.ndarray, np.ndarray]]:
    if window % 2 == 0:
        raise ValueError("Window size must be odd.")
    if order >= window:
        raise ValueError("Order must be less than window size.")

    half_size = window // 2
    exps = [(i, j) for i in range(order + 1) for j in range(order + 1 - i)]

    ind = np.arange(-half_size, half_size + 1, dtype=np.float64)
    dx = np.repeat(ind, window)
    dy = np.tile(ind, window)

    A = np.empty((window * window, len(exps)))
    for k, (i, j) in enumerate(exps):
        A[:, k] = (dx**i) * (dy**j)

    # Compute the pseudo-inverse of A
    A_pinv = np.linalg.pinv(A)

    # Prepare the padded input array
    Z = np.pad(z, ((half_size, half_size), (half_size, half_size)), mode='edge')

    # Prepare output arrays
    result = np.zeros_like(z)
    if deriv in ['both', 1]:
        result_dx = np.zeros_like(z)
    if deriv in ['both', 2]:
        result_dy = np.zeros_like(z)

    # Convolve
    for i in range(half_size, Z.shape[0] - half_size):
        for j in range(half_size, Z.shape[1] - half_size):
            window_data = Z[i - half_size:i + half_size + 1, j - half_size:j + half_size + 1].ravel()
            coeffs = A_pinv @ window_data

            if deriv is None or deriv == 0:
                result[i - half_size, j - half_size] = coeffs[0]
            if deriv in ['both', 1]:
                result_dx[i - half_size, j - half_size] = coeffs[1]
            if deriv in ['both', 2]:
                result_dy[i - half_size, j - half_size] = coeffs[order + 1]

    if deriv is None or deriv == 0:
        return result
    elif deriv in ['both', 1]:
        return result_dx, result_dy
    elif deriv in ['col', 2]:
        return result_dy
    elif deriv in ['row', 3]:
        return result_dx
