import numpy as np
from scipy import stats as sps

def fit(spsdotwhat, x, fwords):
    if len(np.unique(x)) < 2:
        return None

    try:
        shape_loc_scale = spsdotwhat.fit(x, **fwords)
    except Exception:
        shape_loc_scale = (np.nan, np.nan, np.nan)

    if not check_shape_loc_scale(spsdotwhat, shape_loc_scale):
        if spsdotwhat == sps.gamma:
            mean = np.mean(x)
            var = np.var(x)
            shape = mean**2 / var
            scale = var / mean
            shape_loc_scale = (shape, 0, scale)
        elif spsdotwhat == sps.beta:
            x_min, x_max = np.min(x), np.max(x)
            x_norm = (x - x_min) / (x_max - x_min)
            mean = np.mean(x_norm)
            var = np.var(x_norm)
            p = mean * (mean * (1 - mean) / var - 1)
            q = (1 - mean) * (mean * (1 - mean) / var - 1)
            shape_loc_scale = (p, q, x_min, x_max - x_min)

    if not check_shape_loc_scale(spsdotwhat, shape_loc_scale):
        return None

    ks_stat, _ = sps.kstest(x, spsdotwhat.name, args=shape_loc_scale)
    if ks_stat > 0.5:
        return None

    return shape_loc_scale

def check_shape_loc_scale(spsdotwhat, params):
    if any(np.isnan(params)) or any(np.isinf(params)):
        return False

    if spsdotwhat == sps.norm:
        _, loc, scale = params
        if scale <= 0:
            return False
    elif spsdotwhat in [sps.weibull_min, sps.gamma, sps.rice]:
        shape, loc, scale = params
        if shape <= 0 or scale <= 0:
            return False
    elif spsdotwhat == sps.beta:
        p, q, loc, scale = params
        if p <= 0 or q <= 0 or p > 1e10 or q > 1e10:
            return False

    return True
