import numpy as np
from scipy import signal

def preprocess_signal(sg):
    if sg is None or not isinstance(sg, np.ndarray):
        return None
    sg = np.nan_to_num(sg)
    sg_min, sg_max = sg.min(), sg.max()
    if sg_max > sg_min:
        sg = (sg - sg_min) / (sg_max - sg_min)
    return sg

def postprocess_signal(sg):
    sg = np.clip(sg, -1, 1)
    return sg * 1000

def signal_filter(sg, freq, fr, order, mode, remove_mean):
    step = 10000

    sg = preprocess_signal(sg)
    if sg is None or freq is None or fr is None:
        return None

    if mode in ["bandpass", "bandstop"]:
        if not isinstance(freq, (list, tuple)) or len(freq) != 2:
            return None
        freq = sorted(freq)
        if freq[0] <= 0 or freq[1] >= fr:
            return None
        freq = [f / fr for f in freq]
    else:
        if not (0 < freq < fr):
            return None
        freq = freq / fr

    try:
        b, a = signal.butter(order, freq, btype=mode)
    except ValueError:
        return None

    filtered_signal = np.zeros_like(sg)
    for start in range(0, sg.shape[0], step):
        end = min(start + step, sg.shape[0])
        chunk = sg[start:end]
        if remove_mean:
            chunk = chunk - np.mean(chunk, axis=0)
        filtered_chunk = signal.filtfilt(b, a, chunk, axis=0)
        filtered_signal[start:end] = filtered_chunk

    filtered_signal = postprocess_signal(filtered_signal)
    return filtered_signal
