import numpy as np

def _contains_nan(a, nan_policy):
    if nan_policy not in ['propagate', 'omit']:
        raise ValueError("nan_policy must be 'propagate' or 'omit'")
    contains_nan = np.isnan(a).any()
    if contains_nan and nan_policy == 'propagate':
        return True, np.nan
    return contains_nan, None

def percentileofscore(a, score, kind='rank', nan_policy='omit'):
    a = np.asarray(a)
    score = np.asarray(score)

    contains_nan_a, result_a = _contains_nan(a, nan_policy)
    contains_nan_score, result_score = _contains_nan(score, nan_policy)

    if contains_nan_a or contains_nan_score:
        if nan_policy == 'propagate':
            return np.full(score.shape, np.nan)
        elif nan_policy == 'omit':
            a = a[~np.isnan(a)]
            score = score[~np.isnan(score)]

    n = len(a)
    if n == 0:
        return np.full(score.shape, np.nan)

    score = np.atleast_1d(score)
    result = np.empty(score.shape, dtype=float)

    for i, s in enumerate(score):
        if kind == 'rank':
            count = np.sum(a < s) + 0.5 * np.sum(a == s)
            result[i] = 100.0 * count / n
        elif kind == 'strict':
            count = np.sum(a < s)
            result[i] = 100.0 * count / n
        elif kind == 'weak':
            count = np.sum(a <= s)
            result[i] = 100.0 * count / n
        elif kind == 'mean':
            count_strict = np.sum(a < s)
            count_rank = count_strict + 0.5 * np.sum(a == s)
            result[i] = 100.0 * (count_strict + count_rank) / (2 * n)
        else:
            result[i] = np.nan

    if result.ndim == 0:
        return float(result)
    return result
