    unique_values = np.unique(y_train)
    if y_train.dtype.kind in 'if' and len(unique_values) > 20:
        return 'regression'
    elif len(unique_values) == 2:
        return 'binary'
    else:
        return 'multiclass'

def simple_model(X_train, y_train, X_test):
    seed = 42

    if isinstance(y_train, np.ndarray):
        y_train = pd.Series(y_train, index=X_train.index)

    problem_type = analyze_problem_type(y_train)

    model_params = {
        'regression': {
            'objective': 'regression',
            'metric': 'rmse'
        },
        'binary': {
            'objective': 'binary',
            'metric': 'binary_logloss'
        },
        'multiclass': {
            'objective': 'multiclass',
            'metric': 'multi_logloss'
        }
    }

    params = model_params[problem_type]
    params.update({
        'boosting_type': 'gbdt',
        'verbose': -1,
        'seed': seed,
        'feature_fraction': 0.9,
        'bagging_fraction': 0.8,
        'max_depth': -1,
        'n_estimators': 100,
        'num_leaves': 31,
        'min_data_in_leaf': 20,
        'subsample_freq': 1
    })

    if problem_type != 'regression':
        params['num_class'] = len(np.unique(y_train)) if problem_type == 'multiclass' else 1
        params['is_unbalance'] = True

    if problem_type == 'regression':
        model = LGBMRegressor(**params)
    else:
        model = LGBMClassifier(**params)

    model.fit(X_train, y_train)

    predictions = model.predict(X_test)

    if problem_type != 'regression':
        probabilities = model.predict_proba(X_test)
        scaler = MinMaxScaler()
