from sklearn.model_selection import GridSearchCV, RandomizedSearchCV, KFold
from sklearn.tree import DecisionTreeClassifier, DecisionTreeRegressor
from sklearn.metrics import make_scorer, accuracy_score, mean_squared_error
import numpy as np

def grid_search_with_multioutput_data(X, y):
    # Determine if the task is classification or regression
    if len(np.unique(y)) < 10:
        task_type = 'classification'
    else:
        task_type = 'regression'

    # Preprocess target variable for classification
    if task_type == 'classification' and y.ndim > 1:
        y = np.argmax(y, axis=1)

    # Define hyperparameter grid
    est_parameters = {'max_depth': list(range(1, 5))}

    # Initialize estimators based on task type
    if task_type == 'classification':
        estimators = [DecisionTreeClassifier()]
        scoring = make_scorer(accuracy_score)
    else:
        estimators = [DecisionTreeRegressor()]
        scoring = make_scorer(mean_squared_error, greater_is_better=False)

    results = {}

    # Perform Grid Search
    for estimator in estimators:
        grid_search = GridSearchCV(estimator, est_parameters, cv=KFold(n_splits=5), scoring=scoring)
        grid_search.fit(X, y)

        # Store results
        est_name = estimator.__class__.__name__
        results[f'GridSearch_{est_name}'] = {}

        for idx, params in enumerate(grid_search.cv_results_['params']):
            candidate_key = f'candidate_{idx}'
            results[f'GridSearch_{est_name}'][candidate_key] = grid_search.cv_results_['mean_test_score'][idx]

    # Perform Randomized Search
    for estimator in estimators:
        randomized_search = RandomizedSearchCV(estimator, est_parameters, n_iter=3, cv=KFold(n_splits=5), scoring=scoring)
        randomized_search.fit(X, y)

        # Store results
        est_name = estimator.__class__.__name__
        results[f'RandomSearch_{est_name}'] = {}

        for idx, params in enumerate(randomized_search.cv_results_['params']):
            candidate_key = f'candidate_{idx}'
            results[f'RandomSearch_{est_name}'][candidate_key] = randomized_search.cv_results_['mean_test_score'][idx]

    return results
