    # Squeeze y_train and y_test if they have three dimensions
    if y_train.ndim == 3:
        y_train = np.squeeze(y_train, axis=-1)
    if y_test.ndim == 3:
        y_test = np.squeeze(y_test, axis=-1)

    # Check if y_test has only one output dimension
    if y_test.shape[-1] == 1:
        # Define models
        models = {
            'GCN+rf': RandomForestRegressor(),
            'GCN+svm': SVR(C=0.8),
            'GCN+knn': KNeighborsRegressor()
        }

        # Train and evaluate each model
        for name, model in models.items():
            model.fit(X_train, y_train.ravel())
            predictions = model.predict(X_test)
            rmse = np.sqrt(mean_squared_error(y_test, predictions))
            scores.append((name, rmse))
    else:
        # Multi-output case
        results = {name: [] for name in ['GCN+rf', 'GCN+svm', 'GCN+knn']}

        for i in range(y_test.shape[1]):
            if np.max(y_train[:, i]) == 0 or np.max(y_test[:, i]) == 0:
                continue

            models = {
                'GCN+rf': RandomForestRegressor(),
                'GCN+svm': SVR(C=0.8),
                'GCN+knn': KNeighborsRegressor()
            }

            for name, model in models.items():
                model.fit(X_train, y_train[:, i])
                predictions = model.predict(X_test)
                rmse = np.sqrt(mean_squared_error(y_test[:, i], predictions))
                results[name].append(rmse)

        for name in results:
            if results[name]:
                mean_rmse = np.mean(results[name])
                scores.append((name, mean_rmse))

    # Return results as a DataFrame
    if scores:
        return pd.DataFrame(scores, columns=['Model', 'RMSE'])
    else:
        return pd.DataFrame(columns=['Model', 'RMSE'])
