import numpy as np
from sklearn.linear_model import LogisticRegression
from sklearn.ensemble import RandomForestClassifier
from sklearn.svm import SVC
from sklearn.tree import DecisionTreeClassifier
from sklearn.neighbors import KNeighborsClassifier
from sklearn.metrics import accuracy_score, f1_score, roc_auc_score, log_loss, confusion_matrix

def get_base_model(classifier: str, n_classes: int):
    if classifier == 'LR':
        return LogisticRegression(max_iter=1000)
    elif classifier == 'RF':
        return RandomForestClassifier()
    elif classifier == 'SVM':
        return SVC(probability=True)
    elif classifier == 'DT':
        return DecisionTreeClassifier()
    elif classifier == 'KNN':
        return KNeighborsClassifier()
    else:
        raise ValueError("Unsupported classifier type")

def specificity(y_true, y_pred):
    tn, fp, fn, tp = confusion_matrix(y_true, y_pred).ravel()
    return tn / (tn + fp) if (tn + fp) > 0 else 0

def sensitivity(y_true, y_pred):
    tn, fp, fn, tp = confusion_matrix(y_true, y_pred).ravel()
    return tp / (tp + fn) if (tp + fn) > 0 else 0

def evaluate_cac(X: np.ndarray, y: np.ndarray, cluster_labels: np.ndarray, classifier: str) -> tuple:
    y_pred = []
    y_true = []
    y_proba = []
    models = []
    loss = []

    for cluster in np.unique(cluster_labels):
        indices = np.where(cluster_labels == cluster)[0]
        if len(indices) < 5:
            continue

        x_cluster = X[indices]
        y_cluster = y[indices]

        if len(np.unique(y_cluster)) < 2:
            continue

        model = get_base_model(classifier, len(np.unique(y_cluster)))
        model.fit(x_cluster, y_cluster)

        pred = model.predict(x_cluster)
        proba = model.predict_proba(x_cluster)[:, 1]

        y_pred.extend(pred)
        y_true.extend(y_cluster)
        y_proba.extend(proba)

        models.append(model)
        loss.append(log_loss(y_cluster, proba))

    if not y_pred:
        return ([0, 0, 0, 0, 0], float('inf'), models)

    accuracy = accuracy_score(y_true, y_pred)
    f1 = f1_score(y_true, y_pred)
    auc = roc_auc_score(y_true, y_proba)
    conf_matrix = confusion_matrix(y_true, y_pred).ravel()
    spec = specificity(y_true, y_pred)
    sens = sensitivity(y_true, y_pred)
    total_log_loss = np.mean(loss)

    return ([accuracy, f1, auc, spec, sens], total_log_loss, models)
