        auc = 0

    tn, fp, fn, tp = confusion_matrix(y_true, y_pred).ravel()
    spe = tn / (tn + fp) if (tn + fp) > 0 else 0
    sen = tp / (tp + fn) if (tp + fn) > 0 else 0

    total_loss = sum(loss)

    return ([acc, f1, auc, spe, sen], total_loss)
