import numpy as np
from sklearn.utils import indexable, check_consistent_length, _safe_indexing
from sklearn.utils.validation import _num_samples

def size_to_number(size, n_samples):
    if isinstance(size, float):
        return int(np.ceil(size * n_samples))
    elif isinstance(size, int):
        return size
    else:
        raise ValueError("Size must be a float or int.")

def gap_train_test_split(arrays, options):
    arrays = indexable(*arrays)
    check_consistent_length(*arrays)

    n_samples = _num_samples(arrays[0])
    test_size = options.get('test_size', None)
    train_size = options.get('train_size', None)
    gap_size = options.get('gap_size', 0)

    if test_size is None and train_size is None:
        test_size = 0.25

    n_gap = size_to_number(gap_size, n_samples)
    n_remaining = n_samples - n_gap

    if train_size is not None:
        n_train = size_to_number(train_size, n_remaining)
        n_test = n_remaining - n_train
    elif test_size is not None:
        n_test = size_to_number(test_size, n_remaining)
        n_train = n_remaining - n_test
    else:
        raise ValueError("Either train_size or test_size must be specified.")

    if n_train < 0 or n_test < 0:
        raise ValueError("Train size or test size is too large for the given data and gap size.")

    train_indices = range(0, n_train)
    test_indices = range(n_train + n_gap, n_train + n_gap + n_test)

    result = []
    for array in arrays:
        result.append(_safe_indexing(array, train_indices))
        result.append(_safe_indexing(array, test_indices))

    return result
