import tensorflow as tf

def to_int32_64(indices):
    if indices.dtype not in [tf.int32, tf.int64]:
        return tf.cast(indices, tf.int32)
    return indices

def nd_indices(indices):
    batch_size = tf.shape(indices)[0]
    batch_indices = tf.range(batch_size, dtype=indices.dtype)
    batch_indices = tf.expand_dims(batch_indices, axis=-1)
    return tf.concat([batch_indices, tf.expand_dims(indices, axis=-1)], axis=-1)

def batch_gather(x, indices, keepdims: bool) -> tf.Tensor:
    indices = to_int32_64(indices)
    batch_indices = nd_indices(indices)
    y = tf.gather_nd(x, batch_indices)
    if keepdims:
        y = tf.expand_dims(y, axis=1)
    return y
