import tensorflow as tf

def norm2_grad(u, x):
    with tf.GradientTape() as tape:
        tape.watch(x)
        grad = tape.gradient(u, x)
    if grad is not None:
        return tf.reduce_sum(tf.square(grad), axis=-1)
    return tf.constant(0.0, dtype=u.dtype)

def h2(u, x, dimension):
    with tf.GradientTape(persistent=True) as tape:
        tape.watch(x)
        norm2 = norm2_grad(u, x)
        ans = tf.reduce_mean(tf.square(u) + norm2)

    grad = tape.gradient(u, x)
    if grad is not None:
        for i in range(dimension):
            g = tape.gradient(grad[..., i], x)
            if g is not None:
                ans += tf.reduce_mean(tf.reduce_sum(tf.square(g), axis=-1))

    del tape  # Clean up the tape

    if ans is not None:
        return tf.sqrt(ans)
    return tf.constant(0.0, dtype=u.dtype)
