import tensorflow as tf

def tf_regularization_loss(bias, l2_reg, weights, l1_reg):
    losses = []

    if l2_reg > 0:
        l2_loss_weights = tf.nn.l2_loss(weights)
        losses.append(l2_reg * l2_loss_weights)
        if bias is not None:
            l2_loss_bias = tf.nn.l2_loss(bias)
            losses.append(l2_reg * l2_loss_bias)

    if l1_reg > 0:
        l1_loss_weights = tf.reduce_sum(tf.abs(weights))
        losses.append(l1_reg * l1_loss_weights)
        if bias is not None:
            l1_loss_bias = tf.reduce_sum(tf.abs(bias))
            losses.append(l1_reg * l1_loss_bias)

    if losses:
        return tf.add_n(losses)
    else:
        return tf.constant(0.0)

