def tf_regularization_loss(bias, l2_regularization, filters, nonlinearity, l1_regularization):
    losses = []

    if l2_regularization > 0.0:
        l2_loss_filters = tf.nn.l2_loss(filters) * l2_regularization
        losses.append(l2_loss_filters)
        if bias is not None:
            l2_loss_bias = tf.nn.l2_loss(bias) * l2_regularization
