import numpy as np

def sigmoid(x):
    return 1 / (1 + np.exp(-x))

def calculate_state(probabilities):
    return np.random.binomial(1, probabilities)

def parallel_sample(inpt, n_step_MC, p_0, p_1, n_chains, save_evolution,
                    hidden_biases, visible_biases, weights, _v_dim):
    if inpt is None or len(inpt) == 0:
        inpt = np.random.choice([0, 1], size=(n_chains, _v_dim), p=[p_0, p_1])
    elif inpt.ndim != 2:
        inpt = inpt.reshape(n_chains, _v_dim)

    if save_evolution:
        evolution = np.zeros((n_step_MC + 1, n_chains, _v_dim))
        evolution[0] = inpt

    visible_states = inpt

    for step in range(n_step_MC):
        hidden_probs = sigmoid(np.dot(visible_states, weights.T) + hidden_biases)
        hidden_states = calculate_state(hidden_probs)

        visible_probs = sigmoid(np.dot(hidden_states, weights) + visible_biases)
        visible_states = calculate_state(visible_probs)

        if save_evolution:
            evolution[step + 1] = visible_states

    if save_evolution:
        return visible_states, visible_probs, inpt, evolution
    else:
        return visible_states, visible_probs, inpt
```

