import torch

def torch_Bspline(uv: torch.Tensor, kl: int) -> torch.Tensor:
    if kl == 0:
        return ((1 - uv) ** 3) / 6
    elif kl == 1:
        return (uv ** 3) / 2 - uv ** 2 + 2 / 3
    elif kl == 2:
        return (-3 * uv ** 3 + 3 * uv ** 2 + 3 * uv + 1) / 6
    elif kl == 3:
        return (uv ** 3) / 6
    else:
        return torch.zeros_like(uv)
