import torch

def forward(x: torch.Tensor, y: torch.Tensor, weight: torch.Tensor = None, reduction: str = 'mean', eps: float = 1e-6) -> torch.Tensor:
    # Calculate the difference between the tensors
    diff = x - y

    # Calculate the square root of the squared differences with eps added for stability
    sqrt_diff = torch.sqrt(diff ** 2 + eps)

    # Initialize loss
    loss = None

    # Apply reduction method
    if reduction == 'sum':
        if weight is None:
            loss = sqrt_diff.sum() / x.shape[0]
        else:
            loss = (sqrt_diff * weight.view(-1, 1)).sum() / x.shape[0]
    elif reduction == 'mean':
        if weight is None:
            loss = sqrt_diff.mean()
        else:
            loss = (sqrt_diff * weight.view(-1, 1)).sum() / weight.sum()

    return loss
```

