import numpy as np
from lightgbm import LGBMClassifier, LGBMRegressor
from sklearn.model_selection import train_test_split

def analyze_problem_type(y_train):
    unique_values = np.unique(y_train)
    if len(unique_values) == 2:
        return 'binary'
    elif len(unique_values) > 2 and y_train.dtype.kind in 'iufc':
        return 'multiclass'
    else:
        return 'regression'

def simple_LightGBM_model(X_train, y_train, X_test, params=None):
    if params is None:
        params = {}

    problem_type = analyze_problem_type(y_train)

    if problem_type == 'regression':
        model = LGBMRegressor(**params)
        eval_metric = 'l2'
    else:
        model = LGBMClassifier(**params)
        eval_metric = 'logloss'

    X_train_fit, X_val, y_train_fit, y_val = train_test_split(
        X_train, y_train, test_size=0.2, random_state=42
    )

    fit_params = {
        'eval_set': [(X_val, y_val)],
        'eval_metric': eval_metric,
        'early_stopping_rounds': 10,
        'verbose': False
    }

    model.fit(X_train_fit, y_train_fit, **fit_params)

    preds = model.predict(X_test)

    return preds, model
